// Audio Preferences and Shot Sound Playback

// AUDIO SYSTEM
// ═══════════════════════════════════════
const SOUNDS_B64={
  driver:"data:audio/mp3;base64,",
  iron:"data:audio/mp3;base64,",
  sand:"data:audio/mp3;base64,",
  splash:"data:audio/mp3;base64,",
  putt:"data:audio/mp3;base64,",

  cheer:"data:audio/mp3;base64,",
  wildcard:"data:audio/mp3;base64,",

  wc_use:"data:audio/mp3;base64,",
};

// Audio cache — decoded once, reused
let _audioCache={};
let _audioCtx=null;

function getAudioCtx(){
  if(!_audioCtx){
    try{_audioCtx=new(window.AudioContext||window.webkitAudioContext)();}catch(e){}
  }
  // Auto-resume on iOS when returning from background
  if(_audioCtx&&_audioCtx.state==='suspended'){
    _audioCtx.resume().catch(()=>{});
  }
  return _audioCtx;
}

// Resume AudioContext on visibility + interaction (iOS screen lock recovery)
function _resumeAudio(){
  if(!_audioCtx) return;
  // iOS: state can be 'suspended' or 'interrupted' after screen lock
  if(_audioCtx.state==='suspended'||_audioCtx.state==='interrupted'){
    _audioCtx.resume().catch(()=>{
      // If resume fails, recreate the context on next playSound call
      _audioCtx=null;_audioCache={};
    });
  }
}
document.addEventListener('visibilitychange',()=>{
  if(document.visibilityState==='visible') _resumeAudio();
});
document.addEventListener('touchstart',_resumeAudio,{passive:true});
document.addEventListener('click',_resumeAudio,{passive:true});
// pageshow fires when returning from bfcache (iOS safari)
window.addEventListener('pageshow',(e)=>{
  if(e.persisted) _resumeAudio();
});

function soundEnabled(){
  try{return localStorage.getItem("gg_sound")!=="off";}catch{return true;}
}
function setSoundEnabled(v){
  try{localStorage.setItem("gg_sound",v?"on":"off");}catch{}
}

// Decode base64 data URI to ArrayBuffer without fetch (works in all CSP environments)
function _b64ToArrayBuffer(dataUri){
  const b64=dataUri.split(',')[1];
  const binary=atob(b64);
  const bytes=new Uint8Array(binary.length);
  for(let i=0;i<binary.length;i++) bytes[i]=binary.charCodeAt(i);
  return bytes.buffer;
}

async function playSound(name, volume=1.0){
  if(!soundEnabled())return;
  const ctx=getAudioCtx();
  if(!ctx)return;
  
  if(ctx.state==="suspended") {
      try { await ctx.resume(); } catch(e){}
  }
  // Drop the sound event immediately if Safari refuses to wake up the AudioContext
  if(ctx.state==="suspended") return; 

  try{
    let buf=_audioCache[name];
    if(!buf){
      const b64=SOUNDS_B64[name];
      if(!b64)return;
      const arr=_b64ToArrayBuffer(b64);
      buf=await ctx.decodeAudioData(arr);
      _audioCache[name]=buf;
    }
    const src=ctx.createBufferSource();
    src.buffer=buf;
    const gain=ctx.createGain();
    gain.gain.value=volume;
    src.connect(gain);
    gain.connect(ctx.destination);
    src.start(0);
  }catch(e){console.warn("Sound error:",e);}
}

// Map zone keys to sounds
function playShotSound(fromZone, toZone){
  if(toZone==="h2o"){playSound("splash",0.9);return;}
  if(toZone==="ob"){playSound("driver",0.5);return;} // muffled
  if(toZone==="hole"||toZone==="p1"||toZone==="p2"||toZone==="p3"){playSound("putt",1.0);return;}
  if(fromZone==="tee"){playSound("driver",1.0);return;}
  if(fromZone==="sand"){playSound("sand",1.0);return;}
  if(fromZone==="grn"){playSound("putt",0.7);return;}
  // fairway, rough, chip — use iron
  playSound("iron",1.0);
}
// ═══════════════════════════════════════
